import{_ as a,p as i,q as e,a1 as l}from"./framework-96b046e1.js";const h={},r=l('<p>在这里分享一些自己在做 PCBA 维修时的一些心得笔记。</p><h2 id="维修中最容易坏的器件" tabindex="-1"><a class="header-anchor" href="#维修中最容易坏的器件" aria-hidden="true">#</a> 维修中最容易坏的器件</h2><ul><li>电容</li><li>电阻</li><li>二极管</li><li>继电器</li><li>电源芯片</li><li>按键</li><li>开关</li><li>光耦</li><li>运放</li></ul><h3 id="电容" tabindex="-1"><a class="header-anchor" href="#电容" aria-hidden="true">#</a> 电容</h3><p>贴片电容，贴片电容损害时表现为：</p><ul><li>短路：短路时电容的电阻值几乎为0，电路无法工作</li><li>非完全短路：阻止非常低，可能在一百欧姆左右，电容发热严重</li><li>容值变低：使滤波效果变低，有可能使电路工作不稳定</li></ul><p>在电源电路中电容发生损坏的几率比较高。</p><h3 id="电阻" tabindex="-1"><a class="header-anchor" href="#电阻" aria-hidden="true">#</a> 电阻</h3><ul><li>电阻开路：会使电路完全不通</li><li>阻值严重偏离标准值，偏低或高</li></ul><p>电阻损坏会使电路限流或分压电路不准，使电路工作在不正常的状态</p><h3 id="二极管" tabindex="-1"><a class="header-anchor" href="#二极管" aria-hidden="true">#</a> 二极管</h3><ul><li>击穿短路：二极管最常见的损坏就是击穿电路了，会使电路无法工作，发热严重甚至会把电路板烧毁</li><li>TVS 称瞬变电压抑制二极管在 RS485 保护电路中如果漏电流变大可能会影响通信，需要更换新的 TVS管</li></ul><h3 id="继电器" tabindex="-1"><a class="header-anchor" href="#继电器" aria-hidden="true">#</a> 继电器</h3><p>继电器发生损坏的情况为：</p><ul><li>触电粘连：常开触点无法断开</li><li>线圈短路：线圈短路使发热严重，可能会使控制继电器的三极管或MOS管烧掉</li></ul><h3 id="电源芯片" tabindex="-1"><a class="header-anchor" href="#电源芯片" aria-hidden="true">#</a> 电源芯片</h3><p>电源芯片常见的问题有：</p><ul><li>芯片内部损坏，使输出电压不准，需要更换新的</li><li>芯片短路，可能芯片会炸裂，也会使其他保护器件损坏，如：保险、TVS、PCB铜箔等</li></ul><h3 id="按键" tabindex="-1"><a class="header-anchor" href="#按键" aria-hidden="true">#</a> 按键</h3><p>按键使用久了会不灵，需要更换新的</p><h3 id="开关" tabindex="-1"><a class="header-anchor" href="#开关" aria-hidden="true">#</a> 开关</h3><p>有时会发生电路供电偶尔不供电或不稳定，就很有可能是开关的问题，首先要确定开关无问题</p><h3 id="光耦" tabindex="-1"><a class="header-anchor" href="#光耦" aria-hidden="true">#</a> 光耦</h3><p>光耦是控制类器件，损坏时会无法控制，可以用万用表量是否有控制信号，让后看输出的是否可以完全截止和导通</p>',24),d=[r];function n(t,c){return i(),e("div",null,d)}const u=a(h,[["render",n],["__file","debug.html.vue"]]);export{u as default};
